	}
	if claudeEntry.SubscriptionOK {
		t.Fatalf("Claude SubscriptionOK=true, want false for exhausted window: %#v", claudeEntry)
	}
	if claudeEntry.QuotaPercentUsed != 100 || claudeEntry.QuotaTrend != routing.QuotaTrendExhausting {
