	}
	candidates[0].ScoreComponents["base"] = -999
	if out[0].ScoreComponents["base"] != 100 {
		t.Fatalf("event ScoreComponents aliases route candidate map; base=%v, want copied 100", out[0].ScoreComponents["base"])
