	harnessInstanceHook = func(instances map[string]harnesses.Harness) map[string]harnesses.Harness {
		if prev != nil {
			instances = prev(instances)
		}
		instances["claude"] = h
		return instances
	}
	t.Cleanup(func() { harnessInstanceHook = prev })
}

