    family: claude-opus
    status: active
    power: 10
    cost_input_per_m: 15.0
    cost_output_per_m: 75.0
    surfaces:
      claude-code: opus-4.7
`)
	svc := &service{}
	entry := routing.HarnessEntry{
		Name:              "claude",
		Surface:           "claude",
		IsSubscription:    true,
		DefaultModel:      "opus-4.7",
		AutoRoutingModels: []string{"opus-4.7", "sonnet-4.6"},
