	// sonnet-4.6: (3 + 15) / 2 / 1000 = 0.009
	if got := costByModel["sonnet-4.6"]; got != 0.009 {
		t.Errorf("sonnet-4.6 cost=%v, want 0.009 (catalog blended)", got)
